// Convierte el array de issues en items individuales
// para que los siguientes nodos procesen uno por uno
const issues = $input.first().json.issues || [];
return issues.map(issue => ({ json: issue }));

// Datos vienen de Jira Search API: $json.key y $json.fields
const data   = $input.first().json;
const key    = data.key || 'KAN-?';
const fields = data.fields || {};

const summary = fields.summary || 'Sin título';

const getDescription = (d) => {
  if (!d) return 'Sin descripción';
  if (typeof d === 'string') return d;
  try {
    const parts = [];
    (d.content || []).forEach(b => {
      if (b.type === 'paragraph') {
        const t = (b.content || []).map(c => c.text || '').join('');
        if (t.trim()) parts.push(t);
      }
    });
    return parts.join(' ') || 'Sin descripción';
  } catch { return 'Sin descripción'; }
};

const description = getDescription(fields.description);
const priority    = fields.priority?.name          || 'Sin prioridad';
const assignee    = fields.assignee?.displayName   || 'Sin asignar';
const reporter    = fields.reporter?.displayName   || 'Desconocido';
const issueType   = fields.issuetype?.name         || 'Task';
const status      = fields.status?.name            || 'To Do';

const issueUrl   = `https://qaprocess1.atlassian.net/browse/${key}`;
const boardUrl   = 'https://qaprocess1.atlassian.net/jira/software/projects/KAN/boards/1';
const asignarUrl = `https://qaprocess1.atlassian.net/browse/${key}`;

const hoy    = DateTime.now().setLocale('es').toFormat("dd 'de' MMMM 'de' yyyy");
const asunto = `Nuevo Requerimiento Creado - Revisar con el equipo (${hoy})`;

const priorityColors = {
  'Highest': { bg: '#FFEBE6', color: '#BF2600', icon: '🔴' },
  'High':    { bg: '#FFEBE6', color: '#BF2600', icon: '🔴' },
  'Medium':  { bg: '#FFFAE6', color: '#974F0C', icon: '🟡' },
  'Low':     { bg: '#E3FCEF', color: '#006644', icon: '🟢' },
  'Lowest':  { bg: '#E3FCEF', color: '#006644', icon: '🟢' },
};
const pColor = priorityColors[priority] || { bg: '#F4F5F7', color: '#42526E', icon: '⚪' };

const mensajeWhatsApp =
  `🆕 *Nuevo Requerimiento QA — KAN*\n\n` +
  `📋 *[${key}]* ${summary}\n` +
  `🔖 Tipo: ${issueType}\n` +
  `${pColor.icon} Prioridad: ${priority}\n` +
  `👤 Asignado: ${assignee}\n` +
  `📝 Reportado por: ${reporter}\n\n` +
  `🔗 Issue: ${issueUrl}\n` +
  `📌 Board: ${boardUrl}\n\n` +
  `_Revisar con el equipo — ${hoy}_`;

return [{
  json: {
    key, summary, description,
    priority, priorityBg: pColor.bg, priorityColor: pColor.color, priorityIcon: pColor.icon,
    assignee, reporter, issueType, status,
    issueUrl, boardUrl, asignarUrl,
    asunto, hoy, mensajeWhatsApp
  }
}];

const d = $input.first().json;

const headers = [
  'Issue ID','Título','Tipo','Prioridad',
  'Asignado a','Reportado por','Estado',
  'Descripción','Fecha','Link Jira','Board'
];

const row = [
  d.key, d.summary, d.issueType, d.priority,
  d.assignee, d.reporter, d.status,
  d.description, d.hoy, d.issueUrl, d.boardUrl
];

const esc = (v) => `"${String(v || '').replace(/"/g, '""')}"`;

const csvFinal = '\uFEFF' +
  headers.map(esc).join(',') + '\n' +
  row.map(esc).join(',');

const fileName = `Requerimiento-${d.key}-${DateTime.now().toFormat('yyyy-MM-dd')}.csv`;

return [{
  json: d,
  binary: {
    attachment: {
      data: Buffer.from(csvFinal, 'utf-8').toString('base64'),
      mimeType: 'application/vnd.ms-excel',
      fileName: fileName,
      fileExtension: 'csv'
    }
  }
}];
